        val logData = JSONObject().apply {
            put("timestamp", dateFormat.format(Date()))
            put("type", "AUTHENTICATION")
            put("userId", hashedUserId)
            put("authMethod", authMethod)
            put("success", success)
            put("failureReason", failureReason ?: "N/A")
            put("ipAddress", sanitizedIp ?: "UNKNOWN")
            put("deviceInfo", JSONObject(deviceInfo ?: emptyMap()))
        }
        
        val logMessage = "AUTH: User=$hashedUserId, Method=$authMethod, Success=$success" +
                (if (!success) ", Reason=$failureReason" else "")
        
