    fun logApiRequest(
        method: String,
        url: String,
        headers: Map<String, String>,
        requestBody: String?,
        responseCode: Int?,
        responseBody: String?,
        durationMs: Long,
        error: String? = null
    ) {
        val sanitizedHeaders = headers.mapValues { (key, value) ->
            if (key.equals("Authorization", ignoreCase = true) ||
                key.contains("token", ignoreCase = true) ||
