                value
            }
        }
        
        val sanitizedRequestBody = requestBody?.let { sanitizeSensitiveData(it) }
        val sanitizedResponseBody = responseBody?.let { 
            if (it.length > 1000) {
                sanitizeSensitiveData(it.take(1000)) + "... [TRUNCATED]"
            } else {
                sanitizeSensitiveData(it)
            }
        }
        
        val logData = JSONObject().apply {
            put("timestamp", dateFormat.format(Date()))
            put("type", "API_REQUEST")
            put("method", method)
            put("url", url)
