            put("durationMs", durationMs)
            put("error", error ?: "N/A")
        }
        
        val logMessage = "API: $method $url, Code=$responseCode, Time=${durationMs}ms"
        
        when {
            responseCode != null && responseCode >= 500 -> Timber.e(logMessage)
            responseCode != null && responseCode >= 400 -> Timber.w(logMessage)
            else -> Timber.i(logMessage)
        }
        
        writeToFile(logData.toString())
    }

    fun logException(
