        }
        
        val logData = JSONObject().apply {
            put("timestamp", dateFormat.format(Date()))
            put("type", "EXCEPTION")
            put("exceptionType", exception.javaClass.simpleName)
            put("message", exception.message ?: "No message")
            put("stackTrace", stackTrace)
            put("context", context ?: "N/A")
            put("additionalData", JSONObject(sanitizedAdditionalData ?: emptyMap()))
            put("isFatal", isFatal)
        }
        
        val logMessage = "EXCEPTION: ${exception.javaClass.simpleName}" +
                (context?.let { " in $it" } ?: "") +
                ": ${exception.message}"
        
        if (isFatal) {
            Timber.e(exception, logMessage)
        } else {
            Timber.w(exception, logMessage)
        }
        
        writeToFile(logData.toString())
    }

