    inner class SecureTimberTree : Timber.Tree() {
        override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
            val priorityString = when (priority) {
                Log.VERBOSE -> "VERBOSE"
                Log.DEBUG -> "DEBUG"
                Log.INFO -> "INFO"
                Log.WARN -> "WARN"
                Log.ERROR -> "ERROR"
                Log.ASSERT -> "ASSERT"
                else -> "UNKNOWN"
            }
            
            val logEntry = buildString {
                append(dateFormat.format(Date()))
                append(" ")
                append(priorityString)
                append(" ")
                append(tag ?: "NO_TAG")
                append(": ")
                append(sanitizeSensitiveData(message))
                
                t?.let {
                    append("\n")
                    append(StringWriter().also { sw ->
                        it.printStackTrace(PrintWriter(sw))
                    }.toString())
                }
            }
            
            when (priority) {
                Log.VERBOSE -> Log.v(tag, message, t)
                Log.DEBUG -> Log.d(tag, message, t)
                Log.INFO -> Log.i(tag, message, t)
                Log.WARN -> Log.w(tag, message, t)
                Log.ERROR -> Log.e(tag, message, t)
                Log.ASSERT -> Log.wtf(tag, message, t)
            }
        }
    }

